use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion};
use ndarray::{Array1, Array2};
use rand::prelude::*;
use rand_distr::{Normal, Uniform};
use stats_models::{Gaussian, Glm, Lm, Poisson};

fn generate_regression_data(n_obs: usize, n_vars: usize, seed: u64) -> (Array2<f64>, Array1<f64>) {
    let mut rng = StdRng::seed_from_u64(seed);
    let normal = Normal::new(0.0, 1.0).unwrap();
    let uniform = Uniform::new(-1.0, 1.0);

    // Generate design matrix with intercept
    let mut x = Array2::zeros((n_obs, n_vars + 1));
    x.column_mut(0).fill(1.0); // Intercept

    for i in 0..n_obs {
        for j in 1..=n_vars {
            x[[i, j]] = rng.sample(normal);
        }
    }

    // Generate true coefficients
    let true_beta: Array1<f64> = Array1::from_iter((0..=n_vars).map(|_| rng.sample(uniform)));

    // Generate response: y = X*β + ε
    let linear_pred = x.dot(&true_beta);
    let noise: Array1<f64> =
        Array1::from_iter((0..n_obs).map(|_| rng.sample(Normal::new(0.0, 0.1).unwrap())));
    let y = linear_pred + noise;

    (x, y)
}

fn generate_count_data(n_obs: usize, n_vars: usize, seed: u64) -> (Array2<f64>, Array1<f64>) {
    let mut rng = StdRng::seed_from_u64(seed);
    let normal = Normal::new(0.0, 0.5).unwrap();
    let uniform = Uniform::new(-0.5, 0.5);

    // Generate design matrix with intercept
    let mut x = Array2::zeros((n_obs, n_vars + 1));
    x.column_mut(0).fill(1.0); // Intercept

    for i in 0..n_obs {
        for j in 1..=n_vars {
            x[[i, j]] = rng.sample(normal);
        }
    }

    // Generate true coefficients (smaller for count data)
    let true_beta: Array1<f64> = Array1::from_iter((0..=n_vars).map(|_| rng.sample(uniform)));

    // Generate Poisson response: log(μ) = X*β
    let linear_pred = x.dot(&true_beta);
    let mu = linear_pred.mapv(|x| x.exp());

    // Generate Poisson counts (approximated with normal for large μ)
    let y: Array1<f64> = Array1::from_iter(mu.iter().map(|&mu_val| {
        if mu_val > 10.0 {
            // Normal approximation for large μ
            let noise = rng.sample(Normal::new(0.0, mu_val.sqrt()).unwrap());
            (mu_val + noise).max(0.0)
        } else {
            // Simple approximation
            mu_val
                + rng
                    .sample(Normal::new(0.0, mu_val.sqrt() + 0.1).unwrap())
                    .max(-mu_val)
        }
    }));

    (x, y)
}

fn bench_linear_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("Linear Models vs R");

    // Test different problem sizes
    let sizes = [
        (1000, 5),   // Small: 1K obs, 5 predictors
        (10000, 10), // Medium: 10K obs, 10 predictors
        (100000, 5), // Large: 100K obs, 5 predictors
    ];

    for (n_obs, n_vars) in sizes {
        let (x, y) = generate_regression_data(n_obs, n_vars, 42);

        group.bench_with_input(
            BenchmarkId::new("Rust_LM", format!("{}x{}", n_obs, n_vars)),
            &(x.view(), y.view()),
            |b, (x, y)| {
                b.iter(|| {
                    let model = Lm::fit_ndarray(black_box(*x), black_box(*y)).unwrap();
                    black_box(model)
                })
            },
        );
    }

    group.finish();
}

fn bench_glm_models(c: &mut Criterion) {
    let mut group = c.benchmark_group("GLM vs R");

    // Test different problem sizes for Gaussian GLM
    let sizes = [
        (1000, 5),   // Small
        (10000, 10), // Medium
        (50000, 5),  // Large (reduced for GLM as it's slower)
    ];

    for (n_obs, n_vars) in sizes {
        // Gaussian GLM (should be similar to LM)
        let (x, y) = generate_regression_data(n_obs, n_vars, 42);

        group.bench_with_input(
            BenchmarkId::new("Rust_GLM_Gaussian", format!("{}x{}", n_obs, n_vars)),
            &(x.view(), y.view()),
            |b, (x, y)| {
                b.iter(|| {
                    let family = Gaussian;
                    let model =
                        Glm::fit_ndarray(black_box(*x), black_box(*y), family, None, None).unwrap();
                    black_box(model)
                })
            },
        );

        // Poisson GLM
        let (x_count, y_count) = generate_count_data(n_obs, n_vars, 42);

        group.bench_with_input(
            BenchmarkId::new("Rust_GLM_Poisson", format!("{}x{}", n_obs, n_vars)),
            &(x_count.view(), y_count.view()),
            |b, (x, y)| {
                b.iter(|| {
                    let family = Poisson;
                    let model =
                        Glm::fit_ndarray(black_box(*x), black_box(*y), family, None, None).unwrap();
                    black_box(model)
                })
            },
        );
    }

    group.finish();
}

criterion_group!(benches, bench_linear_models, bench_glm_models);
criterion_main!(benches);

