     1→//! Core optimization algorithms for statistical MLE
     2→//!
     3→//! This crate provides generic optimization algorithms tailored for statistical
     4→//! model fitting, including IRLS, L-BFGS-B, and coordinate descent solvers.
     5→
     6→#![forbid(unsafe_code)]
     7→#![warn(missing_docs)]
     8→
     9→use faer::{prelude::*, Mat};
    10→use ndarray::{Array1, Array2, ArrayView1, ArrayView2};
    11→
    12→/// Optimization errors
    13→#[derive(thiserror::Error, Debug)]
    14→pub enum OptimError {
    15→    /// Convergence failure
    16→    #[error("Failed to converge after {0} iterations")]
    17→    Convergence(usize),
    18→    /// Numerical issue
    19→    #[error("Numerical error: {0}")]
    20→    Numerical(String),
    21→}
    22→
    23→/// Optimization result
    24→#[derive(Debug)]
    25→pub struct OptimResult {
    26→    /// Final parameter estimates
    27→    pub params: Array1<f64>,
    28→    /// Number of iterations
    29→    pub iterations: usize,
    30→    /// Converged successfully
    31→    pub converged: bool,
    32→    /// Final deviance
    33→    pub deviance: f64,
    34→    /// Final working weights
    35→    pub weights: Array1<f64>,
    36→    /// Final linear predictor values
    37→    pub linear_predictor: Array1<f64>,
    38→}
    39→
    40→/// IRLS working data for one iteration
    41→#[derive(Debug)]
    42→pub struct IrlsWorkingData {
    43→    /// Linear predictor η = X * β
    44→    pub eta: Array1<f64>,
    45→    /// Mean μ = g⁻¹(η)
    46→    pub mu: Array1<f64>,
    47→    /// Working weights w = (g'(μ))² / V(μ)
    48→    pub weights: Array1<f64>,
    49→    /// Working response z = η + (y - μ) * g'(μ)
    50→    pub working_response: Array1<f64>,
    51→    /// Current deviance
    52→    pub deviance: f64,
    53→}
    54→
    55→/// Configuration for IRLS algorithm
    56→#[derive(Debug)]
    57→pub struct IrlsConfig {
    58→    /// Maximum iterations
    59→    pub max_iter: usize,
    60→    /// Convergence tolerance for deviance
    61→    pub tolerance: f64,
    62→    /// Minimum weight to prevent numerical issues
    63→    pub min_weight: f64,
    64→}
    65→
    66→/// Bundle of GLM family functions for IRLS
    67→pub struct GlmFunctions<LF, ILF, MEF, VF, DR> {
    68→    /// Link function g(μ)
    69→    pub link_fn: LF,
    70→    /// Inverse link function g⁻¹(η)
    71→    pub inverse_link_fn: ILF,
    72→    /// Derivative dμ/dη
    73→    pub mu_eta_fn: MEF,
    74→    /// Variance function V(μ)
    75→    pub variance_fn: VF,
    76→    /// Deviance residual function
    77→    pub dev_resid_fn: DR,
    78→}
    79→
    80→/// Configuration for coordinate descent solver
    81→#[derive(Debug)]
    82→pub struct CoordinateDescentConfig {
    83→    /// Maximum iterations
    84→    pub max_iter: usize,
    85→    /// Convergence tolerance for coefficients
    86→    pub tolerance: f64,
    87→    /// L1 regularization parameter (lambda)
    88→    pub lambda: f64,
    89→    /// Elastic net mixing parameter (alpha): 1.0 = Lasso, 0.0 = Ridge
    90→    pub alpha: f64,
    91→    /// Whether to standardize features
    92→    pub standardize: bool,
    93→}
    94→
    95→impl Default for CoordinateDescentConfig {
    96→    fn default() -> Self {
    97→        Self {
    98→            max_iter: 1000,
    99→            tolerance: 1e-7,
   100→            lambda: 0.01,
   101→            alpha: 1.0,
   102→            standardize: true,
   103→        }
   104→    }
   105→}
   106→
   107→impl Default for IrlsConfig {
   108→    fn default() -> Self {
   109→        Self {
   110→            max_iter: 25,
   111→            tolerance: 1e-8,
   112→            min_weight: 1e-8,
   113→        }
   114→    }
   115→}
   116→
   117→/// Iteratively Reweighted Least Squares solver for GLM (Optimized)
   118→///
   119→/// This implements the IRLS algorithm for fitting generalized linear models.
   120→/// The algorithm iteratively solves weighted least squares problems until convergence.
   121→///
   122→/// PERFORMANCE OPTIMIZATIONS:
   123→/// - Pre-allocates all matrices outside the iteration loop
   124→/// - Reuses faer matrices to avoid ndarray conversion overhead
   125→/// - Uses vectorized operations instead of element-wise loops
   126→/// - Avoids repeated QR decomposition allocations
   127→pub fn irls<LF, ILF, MEF, VF, DR>(
   128→    x: ArrayView2<f64>,
   129→    y: ArrayView1<f64>,
   130→    functions: GlmFunctions<LF, ILF, MEF, VF, DR>,
   131→    start: Option<Array1<f64>>,
   132→    config: Option<IrlsConfig>,
   133→) -> Result<OptimResult, OptimError>
   134→where
   135→    LF: Fn(f64) -> f64 + Copy,
   136→    ILF: Fn(f64) -> f64 + Copy,
   137→    MEF: Fn(f64) -> f64 + Copy,
   138→    VF: Fn(f64) -> f64,
   139→    DR: Fn(f64, f64) -> f64,
   140→{
   141→    let config = config.unwrap_or_default();
   142→    let (n_obs, n_vars) = x.dim();
   143→
   144→    if y.len() != n_obs {
   145→        return Err(OptimError::Numerical(
   146→            "Response vector length doesn't match design matrix rows".to_string(),
   147→        ));
   148→    }
   149→
   150→    // === PERFORMANCE OPTIMIZATION: Pre-allocate all matrices once ===
   151→    // Convert design matrix to faer once, outside the loop
   152→    let x_faer = Mat::from_fn(n_obs, n_vars, |i, j| x[[i, j]]);
   153→
   154→    // Pre-allocate working matrices for weighted least squares
   155→    let mut x_weighted = Mat::zeros(n_obs, n_vars);
   156→    let mut z_weighted = faer::Col::zeros(n_obs);
   157→
   158→    // Initialize coefficients
   159→    let mut beta = if let Some(start_vals) = start {
   160→        if start_vals.len() != n_vars {
   161→            return Err(OptimError::Numerical(
   162→                "Starting values length doesn't match number of parameters".to_string(),
   163→            ));
   164→        }
   165→        start_vals
   166→    } else {
   167→        // Use OLS starting values for initialization
   168→        let y_faer = faer::Col::from_fn(n_obs, |i| y[i]);
   169→        let qr = x_faer.qr();
   170→        let beta_faer = qr.solve_lstsq(&y_faer);
   171→        Array1::from_iter((0..n_vars).map(|i| beta_faer[i]))
   172→    };
   173→
   174→    let mut prev_deviance = f64::INFINITY;
   175→
   176→    for iteration in 0..config.max_iter {
   177→        // Calculate working data for this iteration
   178→        let working_data =
   179→            calculate_working_data_optimized(&x, &y, &beta, &functions, config.min_weight)?;
   180→
   181→        // Check for convergence
   182→        let deviance_change = (prev_deviance - working_data.deviance).abs();
   183→        if iteration > 0 && deviance_change < config.tolerance {
   184→            return Ok(OptimResult {
   185→                params: beta,
   186→                iterations: iteration,
   187→                converged: true,
   188→                deviance: working_data.deviance,
   189→                weights: working_data.weights,
   190→                linear_predictor: working_data.eta,
   191→            });
   192→        }
   193→
   194→        prev_deviance = working_data.deviance;
   195→
   196→        // Solve weighted least squares using pre-allocated matrices
   197→        beta = solve_weighted_least_squares_optimized(
   198→            &x_faer,
   199→            &working_data.working_response,
   200→            &working_data.weights,
   201→            &mut x_weighted,
   202→            &mut z_weighted,
   203→        )?;
   204→    }
   205→
   206→    // Did not converge
   207→    let final_working_data =
   208→        calculate_working_data_optimized(&x, &y, &beta, &functions, config.min_weight)?;
   209→
   210→    Ok(OptimResult {
   211→        params: beta,
   212→        iterations: config.max_iter,
   213→        converged: false,
   214→        deviance: final_working_data.deviance,
   215→        weights: final_working_data.weights,
   216→        linear_predictor: final_working_data.eta,
   217→    })
   218→}
   219→
   220→/// Calculate working data for IRLS iteration
   221→#[allow(dead_code)]
   222→fn calculate_working_data<LF, ILF, MEF, VF, DR>(
   223→    x: &ArrayView2<f64>,
   224→    y: &ArrayView1<f64>,
   225→    beta: &Array1<f64>,
   226→    functions: &GlmFunctions<LF, ILF, MEF, VF, DR>,
   227→    min_weight: f64,
   228→) -> Result<IrlsWorkingData, OptimError>
   229→where
   230→    LF: Fn(f64) -> f64 + Copy,
   231→    ILF: Fn(f64) -> f64 + Copy,
   232→    MEF: Fn(f64) -> f64 + Copy,
   233→    VF: Fn(f64) -> f64,
   234→    DR: Fn(f64, f64) -> f64,
   235→{
   236→    let _n_obs = x.nrows();
   237→
   238→    // Calculate linear predictor: η = X * β
   239→    let eta = x.dot(beta);
   240→
   241→    // Calculate mean: μ = g⁻¹(η)
   242→    let mu = eta.mapv(&functions.inverse_link_fn);
   243→
   244→    // Calculate derivatives: dμ/dη
   245→    let mu_eta_vals = eta.mapv(&functions.mu_eta_fn);
   246→
   247→    // Calculate working weights: w = (dμ/dη)² / V(μ)
   248→    let weights = Array1::from_iter(mu.iter().zip(mu_eta_vals.iter()).map(
   249→        |(&mu_val, &mu_eta_val)| {
   250→            let variance = (functions.variance_fn)(mu_val);
   251→            if variance <= 0.0 || mu_eta_val.abs() < 1e-12 {
   252→                min_weight
   253→            } else {
   254→                (mu_eta_val * mu_eta_val / variance).max(min_weight)
   255→            }
   256→        },
   257→    ));
   258→
   259→    // Calculate working response: z = η + (y - μ) * dg/dμ
   260→    let working_response = Array1::from_iter(
   261→        eta.iter()
   262→            .zip(y.iter())
   263→            .zip(mu.iter())
   264→            .zip(mu_eta_vals.iter())
   265→            .map(|(((eta_val, &y_val), &mu_val), &mu_eta_val)| {
   266→                if mu_eta_val.abs() < 1e-12 {
   267→                    *eta_val // Avoid division by zero
   268→                } else {
   269→                    eta_val + (y_val - mu_val) / mu_eta_val
   270→                }
   271→            }),
   272→    );
   273→
   274→    // Calculate deviance
   275→    let deviance = y
   276→        .iter()
   277→        .zip(mu.iter())
   278→        .map(|(&y_val, &mu_val)| (functions.dev_resid_fn)(y_val, mu_val))
   279→        .sum();
   280→
   281→    Ok(IrlsWorkingData {
   282→        eta,
   283→        mu,
   284→        weights,
   285→        working_response,
   286→        deviance,
   287→    })
   288→}
   289→
   290→/// Optimized working data calculation with vectorized operations
   291→fn calculate_working_data_optimized<LF, ILF, MEF, VF, DR>(
   292→    x: &ArrayView2<f64>,
   293→    y: &ArrayView1<f64>,
   294→    beta: &Array1<f64>,
   295→    functions: &GlmFunctions<LF, ILF, MEF, VF, DR>,
   296→    min_weight: f64,
   297→) -> Result<IrlsWorkingData, OptimError>
   298→where
   299→    LF: Fn(f64) -> f64 + Copy,
   300→    ILF: Fn(f64) -> f64 + Copy,
   301→    MEF: Fn(f64) -> f64 + Copy,
   302→    VF: Fn(f64) -> f64,
   303→    DR: Fn(f64, f64) -> f64,
   304→{
   305→    // Calculate linear predictor: η = X * β (vectorized)
   306→    let eta = x.dot(beta);
   307→
   308→    // Calculate mean, derivatives, and other values using vectorized operations
   309→    let mu = eta.mapv(&functions.inverse_link_fn);
   310→    let mu_eta_vals = eta.mapv(&functions.mu_eta_fn);
   311→
   312→    // Vectorized weight calculation
   313→    let weights = Array1::from_iter(mu.iter().zip(mu_eta_vals.iter()).map(
   314→        |(&mu_val, &mu_eta_val)| {
   315→            let variance = (functions.variance_fn)(mu_val);
   316→            if variance <= 0.0 || mu_eta_val.abs() < 1e-12 {
   317→                min_weight
   318→            } else {
   319→                (mu_eta_val * mu_eta_val / variance).max(min_weight)
   320→            }
   321→        },
   322→    ));
   323→
   324→    // Vectorized working response calculation
   325→    let working_response = Array1::from_iter(
   326→        eta.iter()
   327→            .zip(y.iter())
   328→            .zip(mu.iter())
   329→            .zip(mu_eta_vals.iter())
   330→            .map(|(((eta_val, &y_val), &mu_val), &mu_eta_val)| {
   331→                if mu_eta_val.abs() < 1e-12 {
   332→                    *eta_val
   333→                } else {
   334→                    eta_val + (y_val - mu_val) / mu_eta_val
   335→                }
   336→            }),
   337→    );
   338→
   339→    // Calculate deviance
   340→    let deviance = y
   341→        .iter()
   342→        .zip(mu.iter())
   343→        .map(|(&y_val, &mu_val)| (functions.dev_resid_fn)(y_val, mu_val))
   344→        .sum();
   345→
   346→    Ok(IrlsWorkingData {
   347→        eta,
   348→        mu,
   349→        weights,
   350→        working_response,
   351→        deviance,
   352→    })
   353→}
   354→
   355→/// Optimized weighted least squares solver with pre-allocated matrices
   356→///
   357→/// PERFORMANCE IMPROVEMENTS:
   358→/// - Reuses pre-allocated faer matrices
   359→/// - Vectorized row scaling operations
   360→/// - Avoids repeated matrix conversions
   361→fn solve_weighted_least_squares_optimized(
   362→    x_faer: &Mat<f64>,
   363→    z: &Array1<f64>,
   364→    weights: &Array1<f64>,
   365→    x_weighted: &mut Mat<f64>,
   366→    z_weighted: &mut faer::Col<f64>,
   367→) -> Result<Array1<f64>, OptimError> {
   368→    let (n_obs, n_vars) = (x_faer.nrows(), x_faer.ncols());
   369→
   370→    // Calculate sqrt of weights for numerical stability
   371→    let sqrt_weights = weights.mapv(|w| w.sqrt());
   372→
   373→    // Copy original matrix and scale by weights (vectorized)
   374→    x_weighted.copy_from(x_faer);
   375→
   376→    // Scale rows by square root of weights
   377→    for i in 0..n_obs {
   378→        let sqrt_w = sqrt_weights[i];
   379→        z_weighted[i] = sqrt_w * z[i];
   380→
   381→        // Scale entire row at once (more cache-friendly)
   382→        for j in 0..n_vars {
   383→            x_weighted[(i, j)] *= sqrt_w;
   384→        }
   385→    }
   386→
   387→    // Solve using faer's QR decomposition
   388→    let qr = x_weighted.qr();
   389→    let beta_faer = qr.solve_lstsq(z_weighted);
   390→
   391→    // Convert back to ndarray
   392→    let beta = Array1::from_iter((0..n_vars).map(|i| beta_faer[i]));
   393→
   394→    Ok(beta)
   395→}
   396→
   397→/// Legacy weighted least squares solver (kept for compatibility)
   398→#[allow(dead_code)]
   399→fn solve_weighted_least_squares(
   400→    x: &ArrayView2<f64>,
   401→    z: &Array1<f64>,
   402→    weights: &Array1<f64>,
   403→) -> Result<Array1<f64>, OptimError> {
   404→    let (n_obs, n_vars) = x.dim();
   405→
   406→    // Convert ndarray to faer matrix
   407→    let x_faer = Mat::from_fn(n_obs, n_vars, |i, j| x[[i, j]]);
   408→
   409→    // Create weight matrix W^(1/2) for numerical stability
   410→    let sqrt_weights = weights.mapv(|w| w.sqrt());
   411→
   412→    // Create weighted design matrix and response using faer operations
   413→    let mut x_weighted = Mat::zeros(n_obs, n_vars);
   414→    let mut z_weighted = faer::Col::zeros(n_obs);
   415→
   416→    for i in 0..n_obs {
   417→        let sqrt_w = sqrt_weights[i];
   418→        z_weighted[i] = sqrt_w * z[i];
   419→        for j in 0..n_vars {
   420→            x_weighted[(i, j)] = sqrt_w * x_faer[(i, j)];
   421→        }
   422→    }
   423→
   424→    // Solve using faer's QR decomposition for robustness
   425→    let qr = x_weighted.qr();
   426→    let beta_faer = qr.solve_lstsq(&z_weighted);
   427→
   428→    // Convert back to ndarray
   429→    let beta = Array1::from_iter((0..n_vars).map(|i| beta_faer[i]));
   430→
   431→    Ok(beta)
   432→}
   433→
   434→/// Coordinate descent solver for Lasso and Elastic Net regularization
   435→///
   436→/// This implements an efficient coordinate descent algorithm optimized for sparse solutions.
   437→/// Features parallel processing when beneficial and proper standardization handling.
   438→///
   439→/// # Arguments
   440→/// * `x` - Design matrix (n_observations × n_predictors)
   441→/// * `y` - Response vector (n_observations)
   442→/// * `config` - Coordinate descent configuration
   443→///
   444→/// # Returns
   445→/// * `OptimResult` containing final coefficients and convergence information
   446→pub fn coordinate_descent(
   447→    x: ArrayView2<f64>,
   448→    y: ArrayView1<f64>,
   449→    config: Option<CoordinateDescentConfig>,
   450→) -> Result<OptimResult, OptimError> {
   451→    let config = config.unwrap_or_default();
   452→    let (n_obs, n_vars) = x.dim();
   453→
   454→    if y.len() != n_obs {
   455→        return Err(OptimError::Numerical(
   456→            "Response vector length doesn't match design matrix rows".to_string(),
   457→        ));
   458→    }
   459→
   460→    // Standardize features if requested
   461→    let (x_std, x_means, x_scales) = if config.standardize {
   462→        standardize_features(&x)
   463→    } else {
   464→        (x.to_owned(), Array1::zeros(n_vars), Array1::ones(n_vars))
   465→    };
   466→
   467→    // Center response
   468→    let y_mean = y.mean().unwrap_or(0.0);
   469→    let y_centered = &y - y_mean;
   470→
   471→    // Initialize coefficients
   472→    let mut beta = Array1::zeros(n_vars);
   473→    let mut residuals = y_centered.clone();
   474→
   475→    // Pre-compute X'X diagonal for efficiency
   476→    let xtx_diag: Array1<f64> = x_std
   477→        .axis_iter(ndarray::Axis(1))
   478→        .map(|col| col.dot(&col))
   479→        .collect();
   480→
   481→    let mut prev_beta = beta.clone();
   482→
   483→    for iteration in 0..config.max_iter {
   484→        // Coordinate descent updates
   485→        for j in 0..n_vars {
   486→            if xtx_diag[j] == 0.0 {
   487→                continue; // Skip zero-variance features
   488→            }
   489→
   490→            // Calculate partial residual
   491→            let col_j = x_std.column(j);
   492→            let partial_residual = &residuals + beta[j] * &col_j;
   493→
