   495→            let xty = col_j.dot(&partial_residual);
   496→            let new_beta_j = soft_threshold(xty, config.lambda * config.alpha)
   497→                / (xtx_diag[j] + config.lambda * (1.0 - config.alpha));
   498→
   499→            // Update coefficient and residuals
   500→            let _delta = new_beta_j - beta[j];
   501→            beta[j] = new_beta_j;
   502→            residuals = &partial_residual - new_beta_j * &col_j;
   503→        }
   504→
   505→        // Check convergence
   506→        let max_change = (&beta - &prev_beta)
   507→            .mapv(f64::abs)
   508→            .fold(0.0f64, |acc, &val| acc.max(val));
   509→        if max_change < config.tolerance {
   510→            // Transform coefficients back to original scale
   511→            let final_beta = if config.standardize {
   512→                transform_coefficients_back(&beta, &x_means, &x_scales, y_mean)
   513→            } else {
   514→                beta
   515→            };
   516→
   517→            let linear_predictor = x.dot(&final_beta);
   518→
   519→            return Ok(OptimResult {
   520→                params: final_beta,
   521→                iterations: iteration,
   522→                converged: true,
   523→                deviance: residuals.mapv(|r| r * r).sum(),
   524→                weights: Array1::ones(n_obs), // Unweighted for now
   525→                linear_predictor,
   526→            });
   527→        }
   528→
   529→        prev_beta.assign(&beta);
   530→    }
   531→
   532→    // Did not converge
   533→    let final_beta = if config.standardize {
   534→        transform_coefficients_back(&beta, &x_means, &x_scales, y_mean)
   535→    } else {
   536→        beta
   537→    };
   538→
   539→    let linear_predictor = x.dot(&final_beta);
   540→
   541→    Ok(OptimResult {
   542→        params: final_beta,
   543→        iterations: config.max_iter,
   544→        converged: false,
   545→        deviance: residuals.mapv(|r| r * r).sum(),
   546→        weights: Array1::ones(n_obs),
   547→        linear_predictor,
   548→    })
   549→}
   550→
   551→/// Soft thresholding operator for L1 regularization
   552→fn soft_threshold(z: f64, gamma: f64) -> f64 {
   553→    if z > gamma {
   554→        z - gamma
   555→    } else if z < -gamma {
   556→        z + gamma
   557→    } else {
   558→        0.0
   559→    }
   560→}
   561→
   562→/// Standardize features to have mean 0 and variance 1
   563→fn standardize_features(x: &ArrayView2<f64>) -> (Array2<f64>, Array1<f64>, Array1<f64>) {
   564→    let (_n_obs, n_vars) = x.dim();
   565→    let mut x_std = x.to_owned();
   566→    let mut means = Array1::zeros(n_vars);
   567→    let mut scales = Array1::ones(n_vars);
   568→
   569→    for j in 0..n_vars {
   570→        let col = x.column(j);
   571→        let mean = col.mean().unwrap_or(0.0);
   572→        let var = col.mapv(|x| (x - mean).powi(2)).mean().unwrap_or(1.0);
   573→        let scale = var.sqrt();
   574→
   575→        means[j] = mean;
   576→        scales[j] = if scale > 1e-12 { scale } else { 1.0 };
   577→
   578→        // Standardize column
   579→        for i in 0..col.len() {
   580→            x_std[[i, j]] = (x_std[[i, j]] - mean) / scales[j];
   581→        }
   582→    }
   583→
   584→    (x_std, means, scales)
   585→}
   586→
   587→/// Transform coefficients back to original scale after standardization
   588→fn transform_coefficients_back(
   589→    beta_std: &Array1<f64>,
   590→    x_means: &Array1<f64>,
   591→    x_scales: &Array1<f64>,
   592→    y_mean: f64,
   593→) -> Array1<f64> {
   594→    let n_vars = beta_std.len();
   595→    let mut beta = Array1::zeros(n_vars + 1); // Include intercept
   596→
   597→    // Transform slope coefficients
   598→    for j in 0..n_vars {
   599→        beta[j + 1] = beta_std[j] / x_scales[j];
   600→    }
   601→
   602→    // Calculate intercept
   603→    let intercept_adjustment: f64 = (0..n_vars).map(|j| beta[j + 1] * x_means[j]).sum();
   604→    beta[0] = y_mean - intercept_adjustment;
   605→
   606→    beta
   607→}
