     1→//! Comprehensive R comparison benchmarks
     2→//!
     3→//! This benchmark suite compares our Rust implementation against R's lm()
     4→//! to validate we're meeting our performance targets as defined in CLAUDE.md:
     5→//! - Linear Models: ≥2x faster than R's lm()
     6→
     7→use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
     8→use stats_models::Lm;
     9→use std::fs::File;
    10→use std::io::Write;
    11→use std::process::Command;
    12→use std::time::{SystemTime, UNIX_EPOCH};
    13→
    14→/// Generate test data for benchmarking
    15→fn generate_test_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    16→    // Create design matrix with intercept + random variables
    17→    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    18→    let mut y_data = Vec::with_capacity(n_obs);
    19→
    20→    // Simple deterministic data generation for consistent benchmarks
    21→    for i in 0..n_obs {
    22→        // Intercept column
    23→        x_data.push(1.0);
